#include<bits/stdc++.h>
using namespace std;
int main(){
	int n,a,b[10001],c=0;
	cin>>n>>a;
	for(int i=0;n!=0;i++){
		b[i]=n%a;
		n=n/a;
		c++;
	}for(int j=c-1;j!=-1;j--){
		if(b[j]<10){
			cout<<b[j];}
		else if(b[j]==10)cout<<"A";
		else if(b[j]==11)cout<<"B";
		else if(b[j]==12)cout<<"C";
		else if(b[j]==13)cout<<"D";
		else if(b[j]==14)cout<<"E";
		else if(b[j]==15)cout<<"F";
	}
	return 0;
}
